#include <stdio>
#include #include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <dirent.h>
#include <time.h>
#include <errno.h>

#define MAX_COMMIT_MSG 256
#define MAX_FILES 100
#define MAX_FILENAME 256
#define MAX_HASH 64
#define MAX_REF 256
#define MAX_LINE 1024

typedef struct {
    char hash[MAX_HASH];
    char message[MAX_COMMIT_MSG];
    time_t timestamp;
    char parent[MAX_HASH];
    char files[MAX_FILES][MAX_FILENAME];
    int file_count;
} Commit;

char* get_minigit_dir() {
    static char path[1024];
    getcwd(path, sizeof(path));
    strcat(path, "/.minigit");
    return path;
}

char* get_objects_dir() {
    static char path[1024];
    strcpy(path, get_minigit_dir());
    strcat(path, "/objects");
    return path;
}

char* get_refs_dir() {
    static char path[1024];
    strcpy(path, get_minigit_dir());
    strcat(path, "/refs");
    return path;
}

char* get_head_file() {
    static char path[1024];
    strcpy(path, get_minigit_dir());
    strcat(path, "/HEAD");
    return path;
}

char* get_index_file() {
    static char path[1024];
    strcpy(path, get_minigit_dir());
    strcat(path, "/index");
    return path;
}

int file_exists(const char* path) {
    return access(path, F_OK) == 0;
}

void create_directory(const char* path) {
    if (mkdir(path, 0755) == -1 && errno != EEXIST) {
        perror("mkdir");
        exit(1);
    }
}

void init_repo() {
    char* minigit_dir = get_minigit_dir();
    create_directory(minigit_dir);

    char* objects_dir = get_objects_dir();
    create_directory(objects_dir);

    char* refs_dir = get_refs_dir();
    create_directory(refs_dir);

    char* head_file = get_head_file();
    FILE* head = fopen(head_file, "w");
    if (!head) {
        perror("fopen HEAD");
        exit(1);
    }
    fprintf(head, "ref: refs/heads/main\n");
    fclose(head);

    char* index_file = get_index_file();
    FILE* index = fopen(index_file, "w");
    if (!index) {
        perror("fopen index");
        exit(1);
    }
    fclose(index);
}

char* get_file_hash(const char* filename) {
    static char hash[MAX_HASH];
    FILE* file = fopen(filename, "rb");
    if (!file) {
        perror("fopen");
        exit(1);
    }

    unsigned long hash_val = 5381;
    int c;
    while ((c = fgetc(file)) != EOF) {
        hash_val = ((hash_val << 5) + hash_val) + c;
    }
    fclose(file);

    snprintf(hash, sizeof(hash), "%lx", hash_val);
    return hash;
}

void add_file(const char* filename) {
    if (!file_exists(filename)) {
        fprintf(stderr, "error: %s: No such file\n", filename);
        exit(1);
    }

    char* index_file = get_index_file();
    FILE* index = fopen(index_file, "a");
    if (!index) {
        perror("fopen index");
        exit(1);
    }
    fprintf(index, "%s\n", filename);
    fclose(index);
}

void copy_file(const char* src, const char* dest) {
    FILE* in = fopen(src, "rb");
    if (!in) {
        perror("fopen src");
        exit(1);
    }

    FILE* out = fopen(dest, "wb");
    if (!out) {
        perror("fopen dest");
        exit(1);
    }

    int c;
    while ((c = fgetc(in)) != EOF) {
        fputc(c, out);
    }

    fclose(in);
    fclose(out);
}

void commit_files(const char* commit_hash) {
    char* index_file = get_index_file();
    FILE* index = fopen(index_file, "r");
    if (!index) {
        perror("fopen index");
        exit(1);
    }

    char filename[MAX_FILENAME];
    while (fgets(filename, sizeof(filename), index)) {
        filename[strcspn(filename, "\n")] = 0;

        char* hash = get_file_hash(filename);
        char dest[1024];
        snprintf(dest, sizeof(dest), "%s/%s", get_objects_dir(), hash);

        copy_file(filename, dest);
    }

    fclose(index);
}

char* get_current_branch() {
    static char ref[MAX_REF];
    char* head_file = get_head_file();
    FILE* head = fopen(head_file, "r");
    if (!head) {
        perror("fopen HEAD");
        exit(1);
    }

    fgets(ref, sizeof(ref), head);
    fclose(head);

    if (strncmp(ref, "ref: ", 5) == 0) {
        memmove(ref, ref + 5, strlen(ref + 5) + 1);
    }

    ref[strcspn(ref, "\n")] = 0;
    return ref;
}

char* get_branch_head(const char* branch) {
    static char hash[MAX_HASH];
    char path[1024];
    snprintf(path, sizeof(path), "%s/%s", get_refs_dir(), branch);

    FILE* file = fopen(path, "r");
    if (!file) {
        return NULL;
    }

    fgets(hash, sizeof(hash), file);
    fclose(file);

    hash[strcspn(hash, "\n")] = 0;
    return hash;
}

void set_branch_head(const char* branch, const char* hash) {
    char path[1024];
    snprintf(path, sizeof(path), "%s/%s", get_refs_dir(), branch);

    FILE* file = fopen(path, "w");
    if (!file) {
        perror("fopen branch");
        exit(1);
    }

    fprintf(file, "%s\n", hash);
    fclose(file);
}

void update_head(const char* ref) {
    char* head_file = get_head_file();
    FILE* head = fopen(head_file, "w");
    if (!head) {
        perror("fopen HEAD");
        exit(1);
    }

    if (strlen(ref) == 40) {
        fprintf(head, "%s\n", ref);
    } else {
        fprintf(head, "ref: %s\n", ref);
    }

    fclose(head);
}

char* create_commit_hash() {
    static char hash[MAX_HASH];
    snprintf(hash, sizeof(hash), "%lx", (unsigned long)time(NULL));
    return hash;
}

void write_commit(const char* hash, const char* message, const char* parent) {
    char path[1024];
    snprintf(path, sizeof(path), "%s/%s", get_objects_dir(), hash);

    FILE* file = fopen(path, "w");
    if (!file) {
        perror("fopen commit");
        exit(1);
    }

    fprintf(file, "commit %s\n", hash);
    fprintf(file, "parent %s\n", parent);
    fprintf(file, "message %s\n", message);

    char* index_file = get_index_file();
    FILE* index = fopen(index_file, "r");
    if (!index) {
        perror("fopen index");
        exit(1);
    }

    char filename[MAX_FILENAME];
    while (fgets(filename, sizeof(filename), index)) {
        filename[strcspn(filename, "\n")] = 0;
        char* file_hash = get_file_hash(filename);
        fprintf(file, "%s %s\n", filename, file_hash);
    }

    fclose(index);
    fclose(file);
}

void commit(const char* message) {
    char* commit_hash = create_commit_hash();
    char* current_branch = get_current_branch();
    char* parent = get_branch_head(current_branch);

    commit_files(commit_hash);
    write_commit(commit_hash, message, parent ? parent : "");
    set_branch_head(current_branch, commit_hash);

    printf("Committed %s\n", commit_hash);
}

void read_commit(const char* hash, Commit* commit) {
    char path[1024];
    snprintf(path, sizeof(path), "%s/%s", get_objects_dir(), hash);

    FILE* file = fopen(path, "r");
    if (!file) {
        perror("fopen commit");
        exit(1);
    }

    strcpy(commit->hash, hash);

    char line[MAX_LINE];
    while (fgets(line, sizeof(line), file)) {
        line[strcspn(line, "\n")] = 0;

        if (strncmp(line, "parent ", 7) == 0) {
            strcpy(commit->parent, line + 7);
        } else if (strncmp(line, "message ", 8) == 0) {
            strcpy(commit->message, line + 8);
        } else if (strchr(line, ' ')) {
            char* filename = strtok(line, " ");
            strcpy(commit->files[commit->file_count++], filename);
        }
    }

    fclose(file);
}

void restore_file(const char* filename, const char* hash) {
    char src[1024];
    snprintf(src, sizeof(src), "%s/%s", get_objects_dir(), hash);

    if (!file_exists(src)) {
        unlink(filename);
        return;
    }

    copy_file(src, filename);
}

void restore_commit(const char* hash) {
    Commit commit;
    read_commit(hash, &commit);

    for (int i = 0; i < commit.file_count; i++) {
        char* filename = commit.files[i];
        char* file_hash = get_file_hash(filename);
        restore_file(filename, file_hash);
    }
}

void checkout_branch(const char* branch) {
    char ref[MAX_REF];
    snprintf(ref, sizeof(ref), "refs/heads/%s", branch);

    char* hash = get_branch_head(ref);
    if (!hash) {
        fprintf(stderr, "error: pathspec '%s' did not match any known commit\n", branch);
        exit(1);
    }

    restore_commit(hash);
    update_head(ref);
}

void checkout_commit(const char* hash) {
    if (!file_exists(get_objects_dir())) {
        fprintf(stderr, "error: could not read commit %s\n", hash);
        exit(1);
    }

    char path[1024];
    snprintf(path, sizeof(path), "%s/%s", get_objects_dir(), hash);
    if (!file_exists(path)) {
        fprintf(stderr, "error: could not read commit %s\n", hash);
        exit(1);
    }

    restore_commit(hash);
    update_head(hash);
}

void reset(const char* hash) {
    char* current_branch = get_current_branch();
    set_branch_head(current_branch, hash);
    restore_commit(hash);
}

int main(int argc, char* argv[]) {
    if (argc < 2) {
        fprintf(stderr, "usage: minigit <command> [<args>]\n");
        return 1;
    }

    if (strcmp(argv[1], "init") == 0) {
        init_repo();
        return 0;
    }

    if (!file_exists(get_minigit_dir())) {
        fprintf(stderr, "error: not a minigit repository\n");
        return 1;
    }

    if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            fprintf(stderr, "error: no files specified\n");
            return 1;
        }
        for (int i = 2; i < argc; i++) {
            add_file(argv[i]);
        }
        return 0;
    }

    if (strcmp(argv[1], "commit") == 0) {
        if (argc < 3) {
            fprintf(stderr, "error: no commit message\n");
            return 1;
        }
        char message[MAX_COMMIT_MSG] = "";
        for (int i = 2; i < argc; i++) {
            if (i > 2) strcat(message, " ");
            strcat(message, argv[i]);
        }
        commit(message);
        return 0;
    }

    if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            fprintf(stderr, "error: no commit or branch specified\n");
            return 1;
        }

        if (strlen(argv[2]) == 40) {
            checkout_commit(argv[2]);
        } else {
            checkout_branch(argv[2]);
        }
        return 0;
    }

    if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) {
            fprintf(stderr, "error: no commit specified\n");
            return 1;
        }
        reset(argv[2]);
        return 0;
    }

    fprintf(stderr, "error: unknown command %s\n", argv[1]);
    return 1;
}
